let allData = {{workflowparams:allData}};
const updatedGD = [];
const saveAs = {{workflowparams:saveAs}};
const isForceComplete = {{workflowparams:isForceComplete}};
const pickingSetup = {{node:code_picking_defaults.data.gdSetup}};
const pageStatus = {{workflowparams:pageStatus}}
// skip_picking (internal auto-GR): treat picking as not required across the whole GD
// lifecycle (incl. Created), so no picking_status is stamped and no picking TO is created.
const skipPickingGate = {{node:code_gr_gate.data.skipPicking}} || 0;
if (skipPickingGate === 1 && pickingSetup) { pickingSetup.picking_required = 0; }

// Cancel gate: a Completed Goods Delivery has already moved inventory and
// posted downstream. It cannot be cancelled through this save path — it must
// be reversed via the proper completion-reversal flow. Block the save with a
// clear error, reusing the invalidData -> 400 path (if_vnwLSl9x).
if (saveAs === "Cancelled" && allData.gd_status === "Completed") {
  return {
    allData: allData,
    gd_status: allData.gd_status,
    needCL: "not required",
    picking_status: allData.picking_status,
    packing_status: allData.packing_status,
    needSOCleanUp: 0,
    invalidData: 1,
    invalidDataMessage: "Cannot cancel Goods Delivery " + (allData.delivery_no || "") + " because it is already Completed. Reverse the completion before cancelling."
  };
}

// M:N edit gate: when allow_full_picking=1 AND user is editing a GD that has
// multiple non-terminal Pickings (Created / In Progress), block the save with
// a clear error. Forces user to cancel or complete those Pickings before
// modifying the GD upstream of them. Reuses the invalidData -> 400 path
// (if_vnwLSl9x).
if (
  pickingSetup &&
  pickingSetup.allow_full_picking === 1 &&
  saveAs === "Created" &&
  pageStatus === "Edit"
) {
  const activePickings = ({{node:search_node_NBAQ9gsj.data.data}} || [])
    .filter(function(to) {
      return to.to_status !== "Completed" &&
             to.to_status !== "Cancelled" &&
             to.to_status !== "Draft";
    });
  if (activePickings.length > 1) {
    const list = activePickings
      .map(function(to) { return to.to_id || to.id; })
      .slice(0, 5)
      .join(", ");
    const suffix = activePickings.length > 5
      ? " (+" + (activePickings.length - 5) + " more)"
      : "";
    return {
      allData: allData,
      gd_status: allData.gd_status,
      needCL: "not required",
      picking_status: allData.picking_status,
      packing_status: allData.packing_status,
      needSOCleanUp: 0,
      invalidData: 1,
      invalidDataMessage: "Cannot edit this Goods Delivery while " + activePickings.length + " Pickings are active: " + list + suffix + ". Cancel or complete those Pickings before editing."
    };
  }
}

const skippedRows = [];

// Build flags map from Get Items (only populated when picking_mode=Auto ran).
// Used to detect description-only rows: stock_control=0 AND show_delivery=0.
const itemDataRaw = {{node:search_node_w1NxF9TX.data.data}} || [];
const itemDataArray = Array.isArray(itemDataRaw) ? itemDataRaw : [itemDataRaw];
const itemFlagsMap = {};
for (const it of itemDataArray) {
