  // Descriptive (no-stock) line: material_id empty, OR item has stock_control=0 AND show_delivery=0
  const flags = gdLineItem.material_id ? itemFlagsMap[gdLineItem.material_id] : null;
  const isNonStockNoShow = flags && flags.stock_control === 0 && flags.show_delivery === 0;
  const isDescriptive = !gdLineItem.material_id || gdLineItem.material_id === "" || isNonStockNoShow;
  if (isDescriptive) {
    const hasDescription =
      (gdLineItem.material_name && gdLineItem.material_name !== "") ||
      (gdLineItem.gd_material_desc && gdLineItem.gd_material_desc !== "");
    if (!hasDescription && saveAs !== "Draft") {
      skippedRows.push({
        index: index,
        material_name: "(none)",
        gd_qty: gdLineItem.gd_qty,
        so_no: gdLineItem.so_no || "",
