// Pre-flight gate for the auto Sales Invoice (picking_setup.auto_completed_si).
//
// It has to be a PRE-flight gate even though the SI is only created at the very end: a workflow
// cannot prompt mid-run, so the confirmation has to be a return-then-recall, exactly like the
// auto-GR 408 gate. Nothing is written before this point, so returning 412 here costs the user
// only a re-run, never a partial save.
//
// It sits late on purpose (after credit limit, picking, packing and per-line qty validation) so we
// only ask about a GD that is genuinely about to be saved -- unlike the GR gate, which sits at the
// top and can prompt for a GD that later fails validation.
const saveAs = {{workflowparams:saveAs}};
const autoCompletedSi = Number({{node:code_picking_defaults.data.autoCompletedSi}}) || 0;
const autoSiConfirmed = {{workflowparams:auto_si_confirmed}};
const autoSiSkip = {{workflowparams:auto_si_skip}};
const isPicking = {{workflowparams:isPicking}};
const isPacking = {{workflowparams:isPacking}};

// The client sends these as `data.auto_si_confirmed || ""`, so they arrive as true or "".
const truthy = (v) =>
  v === true || v === 1 || v === "true" || v === "1" || v === "Yes";

// Deliberately NOT gated on auto-GR. A picking-driven completion never confirms auto-GR
// (code_gr_gate needs auto_gr_confirmed, which PickingProcessWorkflow does not send), so an
// internal-trading GD completed through picking gets no Goods Receipt -- yet we still invoice it.
// That is intentional and safe: SItoPIWorkflow drops any SI line whose GD has no linked GR
// ("GD has no linked GR -> drop this line") and returns 200/skipped, so no Purchase Invoice is
// ever created against a receipt that does not exist. The seller invoices; the buyer enters the
// GR and PI manually. Do not "fix" this by suppressing the invoice -- it was a considered call.

let siConfirm = 0;
let doAutoSi = 0;
let msg = "";

// null / undefined / 0 all mean off -- only an explicit 1 enables it.
const eligible = saveAs === "Completed" && autoCompletedSi === 1;

if (!eligible || truthy(autoSiSkip)) {
  // Not eligible, or the user chose to complete without an invoice.
} else if (truthy(autoSiConfirmed)) {
  doAutoSi = 1;
} else if (isPicking === "Yes" || Number(isPacking) === 1) {
  // Picking-/packing-driven completion is headless -- there is nobody to answer a prompt.
  // Enabling auto_completed_si IS the org's consent, so honour it without asking.
  doAutoSi = 1;
} else {
  siConfirm = 412;
  msg =
    "This delivery will be invoiced automatically on completion.<br><br>Auto-create the Sales Invoice?";
}

return { siConfirm: siConfirm, doAutoSi: doAutoSi, msg: msg };

