const saveAs = {{workflowparams:saveAs}}

const updatedSOList = soDataList.map(soDoc => {
  const salesOrderId = soDoc.id

  // Handle Created scenario
  if (saveAs === "Created") {
    // Only update gd_status if it was empty
    let newGDStatus = soDoc.gd_status
    if (!soDoc.gd_status || soDoc.gd_status === "" || soDoc.gd_status === null || soDoc.gd_status === "Cancelled") {
      newGDStatus = "Created"
    }

    return {
      id: soDoc.id,
      so_status: soDoc.so_status,
      gd_status: newGDStatus,
      partially_delivered: soDoc.partially_delivered,
      fully_delivered: soDoc.fully_delivered
    }
  }

  // Handle Cancelled scenario
  if (saveAs === "Cancelled") {
    let newGDStatus = soDoc.gd_status

    // Only update gd_status to "Cancelled" if:
    // 1. gd_status was "Created"
    // 2. All planned_qty in table_so are 0
    if (soDoc.gd_status === "Created") {
      const tableSO = soDoc.table_so || []
      const allPickedQtyZero = tableSO.every(soItem => {
        const plannedQty = parseFloat(soItem.planned_qty || 0)
        return plannedQty === 0
      })

      if (allPickedQtyZero) {
        newGDStatus = "Cancelled"
      }
      // If any planned_qty > 0, keep the current gd_status (don't change to Cancelled)
    }

    return {
      id: soDoc.id,
      so_status: soDoc.so_status,
      gd_status: newGDStatus,
      partially_delivered: soDoc.partially_delivered,
      fully_delivered: soDoc.fully_delivered
    }
  }

  // Handle Completed scenario (existing logic)
  if (saveAs === "Completed") {
    // Get SO line items that belong to this SO from finalSOTable
    const soLineItems = finalSOTable.filter(item => item.sales_order_id === salesOrderId)

    // Also count from table_so for lines not in this GD
    const tableSO = soDoc.table_so || []
    const totalItems = tableSO.length

    let partiallyDeliveredItems = 0
    let fullyDeliveredItems = 0

    // Count from all SO lines (including ones not in this GD)
    tableSO.forEach(soItem => {
      // Check if this item was updated in finalSOTable
      const updatedItem = soLineItems.find(item => item.id === soItem.id)
      const lineToCheck = updatedItem || soItem

      const deliveredQty = parseFloat(lineToCheck.delivered_qty || 0)
      const soQty = parseFloat(lineToCheck.so_quantity || 0)
      const lineStatus = lineToCheck.line_status

      if (lineStatus === "Completed" || (deliveredQty >= soQty && soQty > 0)) {
        partiallyDeliveredItems++
        fullyDeliveredItems++
      } else if (deliveredQty > 0) {
        partiallyDeliveredItems++
      }
    })

    // Determine SO status
    const allItemsComplete = fullyDeliveredItems === totalItems && totalItems > 0
    const anyItemProcessing = partiallyDeliveredItems > 0

    let newSOStatus = soDoc.so_status
    let newGDStatus = soDoc.gd_status

    if (allItemsComplete) {
      newSOStatus = "Completed"
      newGDStatus = "Fully Delivered"
    } else if (anyItemProcessing) {
      newSOStatus = "Processing"
      newGDStatus = "Partially Delivered"
    }

    return {
      id: soDoc.id,
      so_status: newSOStatus,
      gd_status: newGDStatus,
      partially_delivered: `${partiallyDeliveredItems} / ${totalItems}`,
      fully_delivered: `${fullyDeliveredItems} / ${totalItems}`
    }
  }

  // Default: return unchanged
  return {
    id: soDoc.id,
    so_status: soDoc.so_status,
    gd_status: soDoc.gd_status,
    partially_delivered: soDoc.partially_delivered,
    fully_delivered: soDoc.fully_delivered
